using System.Text.Json;
using System.Text.Json.Serialization;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver — resolves any type.
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1️⃣  GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T> directly.
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person>  → Type = {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Ada", 38), personInfo);
Console.WriteLine($"  Serialized: {json}");

// 2️⃣  TryGetTypeInfo<T>() — probe without throwing.
//     With default (reflection) resolver this succeeds for any type:
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
    Console.WriteLine($"TryGetTypeInfo<Person> → found: {info!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<Person> → not available");

// Now create options that use a source-gen context which only knows about Person.
// Asking for a type it doesn't know (e.g. int[]) will return false instead of throwing.
var limited = new JsonSerializerOptions { TypeInfoResolver = PersonOnlyContext.Default };

if (limited.TryGetTypeInfo<int[]>(out JsonTypeInfo<int[]>? arrayInfo))
    Console.WriteLine($"TryGetTypeInfo<int[]> → found: {arrayInfo!.Type.Name}");
else
    Console.WriteLine("TryGetTypeInfo<int[]> → not available (resolver doesn't know this type)");

// ── Types ──────────────────────────────────────────────────────────────
public record Person(string Name, int Age);

[JsonSerializable(typeof(Person))]
public partial class PersonOnlyContext : JsonSerializerContext;

